module sr_flip_flop (
    input wire S,
    input wire R,
    input wire reset,
    input wire RESET,
    output reg Q
);
    always @(posedge reset or posedge RESET) begin
        if (RESET)
            Q <= 0;
        else if (R)
            Q <= 0;
        else if (S)
            Q <= 1;
        // If both S and R are low, Q retains its state.
    end
endmodule
